using System;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth;
    
    public int currency = 500;

    void Start()
    {
        currentHealth = maxHealth;
    }

    // Function to take damage
    public void TakeDamage(int damage)
    {
        currentHealth -= damage;
        
        if (currentHealth <= 0)
        {
            Die();
        }
    }
    
    // Function to add currency
    public bool AddCurrency(int amount)
    {
        if (amount < 0) 
        {
            Debug.LogError("Adding negative currency is not allowed");
            return false;
        }
        
        currency += amount;
        return true;
    }
    
    // Function to subtract currency
    public bool SubtractCurrency(int amount)
    {
        if (amount > currency) 
        {
            Debug.LogError("Insufficient funds");
            return false;
        }
        
        currency -= amount;
        return true;
    }
    
    // Function to handle death of the player
    void Die()
    {
        // Handle death logic here
    }
}